import { startServer } from "./src/server.js";
import { resetDb } from "./src/db.js";
const { server, port } = await startServer({ port: 0 });
const base = `http://localhost:${port}`;
const j = async (r) => ({ s: r.status, b: await r.json().catch(()=>null) });
const post = (p, body, tok) => fetch(base+p, { method:"POST", headers:{ "Content-Type":"application/json", ...(tok?{Authorization:`Bearer ${tok}`}:{}) }, body: JSON.stringify(body) });
let out = [];
// register
out.push(["register", await j(await post("/auth/register",{username:"alice",password:"pw1"}))]);
out.push(["register dup", (await post("/auth/register",{username:"alice",password:"pw1"})).status]);
out.push(["register empty", (await post("/auth/register",{username:"",password:"x"})).status]);
out.push(["login bad", (await post("/auth/login",{username:"alice",password:"WRONG"})).status]);
const login = await j(await post("/auth/login",{username:"alice",password:"pw1"}));
const tok = login.b.token;
out.push(["login", login.s, !!tok]);
out.push(["no-token /projects", (await fetch(base+"/projects")).status]);
const proj = await j(await post("/projects",{name:"P1"}, tok));
out.push(["create project", proj.s, proj.b]);
const pid = proj.b.id;
out.push(["empty name", (await post("/projects",{name:""}, tok)).status]);
out.push(["list projects", await j(await fetch(base+"/projects",{headers:{Authorization:`Bearer ${tok}`}}))]);
out.push(["get 404", (await fetch(base+"/projects/nope",{headers:{Authorization:`Bearer ${tok}`}})).status]);
// tasks
const t = await j(await post(`/projects/${pid}/tasks`,{title:"T1"}, tok));
out.push(["create task", t.s, t.b]);
out.push(["task bad assignee", (await post(`/projects/${pid}/tasks`,{title:"T2",assigneeId:"ghost"}, tok)).status]);
out.push(["task unknown project", (await post(`/projects/zzz/tasks`,{title:"T"}, tok)).status]);
const tid = t.b.id;
const patch = await j(await fetch(base+`/projects/${pid}/tasks/${tid}`,{method:"PATCH",headers:{"Content-Type":"application/json",Authorization:`Bearer ${tok}`},body:JSON.stringify({done:true})}));
out.push(["patch task", patch.s, patch.b.done]);
const list = await j(await fetch(base+`/projects/${pid}/tasks?page=1&pageSize=200`,{headers:{Authorization:`Bearer ${tok}`}}));
out.push(["list tasks (pageSize cap)", list.s, {total:list.b.total, pageSize:list.b.pageSize}]);
const del = await fetch(base+`/projects/${pid}/tasks/${tid}`,{method:"DELETE",headers:{Authorization:`Bearer ${tok}`}});
out.push(["delete task", del.status]);
// cascade: recreate task then delete project
const t2 = await j(await post(`/projects/${pid}/tasks`,{title:"T3"}, tok));
const delP = await fetch(base+`/projects/${pid}`,{method:"DELETE",headers:{Authorization:`Bearer ${tok}`}});
out.push(["delete project (cascade)", delP.status]);
server.close(); resetDb();
console.log(JSON.stringify(out,null,1));
